class Solution:
    def maxTwoEvents(self, events):
        n = len(events)
        best = 0
        for i in range(n):
            s1, e1, v1 = events[i]
            if v1 > best:
                best = v1
            for j in range(n):
                if i == j:
                    continue
                s2, e2, v2 = events[j]
                if e1 < s2 or e2 < s1:
                    if v1 + v2 > best:
                        best = v1 + v2
        return best

