var maxTwoEvents = function(events) {
    const sorted = events.slice().sort((a, b) => a[0] - b[0]);
    const n = sorted.length;
    const starts = sorted.map(e => e[0]);
    const suffixMax = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffixMax[i] = Math.max(suffixMax[i + 1], sorted[i][2]);
    }
    function bisectRight(arr, x) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    let ans = 0;
    for (const [s, e, v] of sorted) {
        const idx = bisectRight(starts, e);
        const bestOther = suffixMax[idx];
        ans = Math.max(ans, v, v + bestOther);
    }
    return ans;
};
